// ─────────────────────────────────────────────────────────────
// SCAN FOR UNPROCESSED BRAIN DUMPS
// Reads all .md files in 00_Inbox/brain-dumps/ and returns
// up to 5 files that have "processed: false" in frontmatter.
// ─────────────────────────────────────────────────────────────
const fs = require('fs');
const path = require('path');

const vaultPath = $env.OBSIDIAN_VAULT_PATH || 'C:/Users/Admin/Desktop/Desktop Folders/Obsidian/Homelab';
const brainDumpDir = path.join(vaultPath, '00_Inbox', 'brain-dumps');

// Ensure directory exists
if (!fs.existsSync(brainDumpDir)) {
  return [{ json: { files: [], count: 0, message: 'brain-dumps directory does not exist' } }];
}

const allFiles = fs.readdirSync(brainDumpDir)
  .filter(f => f.endsWith('.md'))
  .map(f => path.join(brainDumpDir, f));

const unprocessed = [];

for (const filePath of allFiles) {
  if (unprocessed.length >= 5) break;

  try {
    const content = fs.readFileSync(filePath, 'utf8');
    // Check frontmatter for processed: false
    const fmMatch = content.match(/^---\n([\s\S]*?)\n---/);
    if (fmMatch) {
      const frontmatter = fmMatch[1];
      if (/processed:\s*false/.test(frontmatter)) {
        unprocessed.push({
          filePath: filePath,
          fileName: path.basename(filePath)
        });
      }
    }
  } catch (err) {
    // Skip files that can't be read
    continue;
  }
}

if (unprocessed.length === 0) {
  return [{ json: { files: [], count: 0, message: 'No unprocessed brain dumps found' } }];
}

return unprocessed.map(f => ({ json: f }));

// ─────────────────────────────────────────────────────────────
// READ FILE CONTENT
// Reads the brain dump file, separates frontmatter from body.
// ─────────────────────────────────────────────────────────────
const fs = require('fs');

const filePath = $input.item.json.filePath;
const fileName = $input.item.json.fileName;

try {
  const content = fs.readFileSync(filePath, 'utf8');

  // Split frontmatter from body
  const parts = content.split('---');
  // parts[0] = '' (before first ---)
  // parts[1] = frontmatter content
  // parts[2..] = body content
  const frontmatter = parts.length > 1 ? parts[1].trim() : '';
  const body = parts.length > 2 ? parts.slice(2).join('---').trim() : '';

  if (!body || body.length < 10) {
    return [{
      json: {
        filePath,
        fileName,
        frontmatter,
        body: '',
        error: true,
        errorMessage: 'Brain dump body is empty or too short (less than 10 chars)'
      }
    }];
  }

  return [{
    json: {
      filePath,
      fileName,
      frontmatter,
      body,
      error: false
    }
  }];
} catch (err) {
  return [{
    json: {
      filePath,
      fileName,
      error: true,
      errorMessage: `Failed to read file: ${err.message}`
    }
  }];
}

// ─────────────────────────────────────────────────────────────
// PARSE AND VALIDATE CLAUDE'S RESPONSE
// Extracts JSON from the API response, validates structure,
// whitelists area and priority values.
// ─────────────────────────────────────────────────────────────
const VALID_AREAS = ['work', 'consulting', 'business', 'personal', 'faith', 'health'];
const VALID_PRIORITIES = ['A', 'B', 'C'];

const filePath = $('Read File Content').item.json.filePath;
const fileName = $('Read File Content').item.json.fileName;

try {
  const response = $input.item.json;

  // Handle HTTP error status
  if (response.statusCode && response.statusCode >= 400) {
    return [{
      json: {
        filePath,
        fileName,
        error: true,
        errorMessage: `Claude API returned HTTP ${response.statusCode}: ${JSON.stringify(response.body || {})}`
      }
    }];
  }

  // Extract text content from Claude API response
  const body = response.body || response;
  let textContent = '';

  if (body.content && Array.isArray(body.content)) {
    const textBlock = body.content.find(c => c.type === 'text');
    textContent = textBlock ? textBlock.text : '';
  } else if (typeof body === 'string') {
    textContent = body;
  } else {
    textContent = JSON.stringify(body);
  }

  // Strip markdown code fences if present
  textContent = textContent.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();

  // Parse JSON
  let parsed;
  try {
    parsed = JSON.parse(textContent);
  } catch (parseErr) {
    // Try to find JSON object in the text
    const jsonMatch = textContent.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      parsed = JSON.parse(jsonMatch[0]);
    } else {
      throw new Error(`Could not parse JSON from Claude response: ${textContent.substring(0, 200)}`);
    }
  }

  // Validate structure
  if (!parsed.tasks && !parsed.notes) {
    throw new Error('Response missing both tasks and notes arrays');
  }

  const tasks = Array.isArray(parsed.tasks) ? parsed.tasks : [];
  const notes = Array.isArray(parsed.notes) ? parsed.notes : [];

  // Validate and sanitize tasks
  const validatedTasks = tasks
    .filter(t => t.title && typeof t.title === 'string')
    .map(t => ({
      title: t.title.trim(),
      area: VALID_AREAS.includes(t.area) ? t.area : 'personal',
      priority: VALID_PRIORITIES.includes(t.priority) ? t.priority : 'B',
      due: t.due && /^\d{4}-\d{2}-\d{2}$/.test(t.due) ? t.due : null,
      context: t.context || null
    }));

  // Validate and sanitize notes
  const validatedNotes = notes
    .filter(n => n.title && typeof n.title === 'string' && n.content)
    .map(n => ({
      title: n.title.trim(),
      area: VALID_AREAS.includes(n.area) ? n.area : 'personal',
      content: n.content.trim()
    }));

  if (validatedTasks.length === 0 && validatedNotes.length === 0) {
    throw new Error('No valid tasks or notes after validation');
  }

  return [{
    json: {
      filePath,
      fileName,
      tasks: validatedTasks,
      notes: validatedNotes,
      taskCount: validatedTasks.length,
      noteCount: validatedNotes.length,
      error: false
    }
  }];

} catch (err) {
  return [{
    json: {
      filePath,
      fileName,
      error: true,
      errorMessage: `Parse/validation error: ${err.message}`
    }
  }];
}

// ─────────────────────────────────────────────────────────────
// WRITE TASK FILES & NOTE FILES
// Creates individual task files in 00_Inbox/processed/
// Creates note files in the appropriate domain folder.
// Then marks the original brain dump as processed.
// ─────────────────────────────────────────────────────────────
const fs = require('fs');
const path = require('path');

const vaultPath = $env.OBSIDIAN_VAULT_PATH || 'C:/Users/Admin/Desktop/Desktop Folders/Obsidian/Homelab';

const data = $input.item.json;
const { filePath, fileName, tasks, notes } = data;

// Area-to-folder mapping for notes
const AREA_FOLDER_MAP = {
  'work': '20_Domains (Life and Work)/Career/Parallon',
  'consulting': '20_Domains (Life and Work)/Career/Consulting',
  'business': '20_Domains (Life and Work)/Personal/Business Ideas & Projects',
  'personal': '20_Domains (Life and Work)/Personal',
  'faith': '30_Knowledge Library/Bible Studies & Notes',
  'health': '30_Knowledge Library/Biohacking'
};

const now = new Date();
const datePrefix = now.toISOString().slice(0, 10);
const timePrefix = now.toISOString().slice(11, 16).replace(':', '');
const timestamp = `${datePrefix}T${now.toISOString().slice(11, 19)}`;

// Helper: create slug from title
function slugify(text) {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '')
    .substring(0, 50);
}

// Helper: ensure directory exists
function ensureDir(dirPath) {
  if (!fs.existsSync(dirPath)) {
    fs.mkdirSync(dirPath, { recursive: true });
  }
}

const results = {
  tasksWritten: 0,
  notesWritten: 0,
  errors: []
};

// ── WRITE TASK FILES ────────────────────────────────────────
const processedDir = path.join(vaultPath, '00_Inbox', 'processed');
ensureDir(processedDir);

for (let i = 0; i < tasks.length; i++) {
  const task = tasks[i];
  const slug = slugify(task.title);
  const taskFileName = `${datePrefix}-${timePrefix}-task-${slug}.md`;
  const taskFilePath = path.join(processedDir, taskFileName);

  // Build task line with inline fields
  let taskLine = `- [ ] ${task.title} [area:: ${task.area}] [priority:: ${task.priority}]`;
  if (task.due) {
    taskLine += ` [due:: ${task.due}]`;
  }

  // Build file content
  let content = '---\n';
  content += 'type: processed-task\n';
  content += 'source: brain-dump\n';
  content += `source_file: ${fileName}\n`;
  content += `created: ${timestamp}\n`;
  content += '---\n\n';
  content += taskLine + '\n';
  if (task.context) {
    content += `\n> ${task.context}\n`;
  }

  try {
    fs.writeFileSync(taskFilePath, content, 'utf8');
    results.tasksWritten++;
  } catch (err) {
    results.errors.push(`Failed to write task file ${taskFileName}: ${err.message}`);
  }
}

// ── WRITE NOTE FILES ────────────────────────────────────────
for (let i = 0; i < notes.length; i++) {
  const note = notes[i];
  const slug = slugify(note.title);
  const noteFileName = `${datePrefix}-${timePrefix}-${slug}.md`;
  const areaFolder = AREA_FOLDER_MAP[note.area] || AREA_FOLDER_MAP['personal'];
  const noteDir = path.join(vaultPath, areaFolder);
  ensureDir(noteDir);
  const noteFilePath = path.join(noteDir, noteFileName);

  let content = '---\n';
  content += 'type: processed-note\n';
  content += 'source: brain-dump\n';
  content += `source_file: ${fileName}\n`;
  content += `area: ${note.area}\n`;
  content += `created: ${timestamp}\n`;
  content += '---\n\n';
  content += `# ${note.title}\n\n`;
  content += note.content + '\n';

  try {
    fs.writeFileSync(noteFilePath, content, 'utf8');
    results.notesWritten++;
  } catch (err) {
    results.errors.push(`Failed to write note file ${noteFileName}: ${err.message}`);
  }
}

// ── MARK ORIGINAL FILE AS PROCESSED ─────────────────────────
try {
  let originalContent = fs.readFileSync(filePath, 'utf8');
  originalContent = originalContent.replace(
    /processed:\s*false/,
    `processed: true\nprocessed_at: ${timestamp}`
  );
  fs.writeFileSync(filePath, originalContent, 'utf8');
} catch (err) {
  results.errors.push(`Failed to mark original as processed: ${err.message}`);
}

return [{
  json: {
    filePath,
    fileName,
    tasksWritten: results.tasksWritten,
    notesWritten: results.notesWritten,
    writeErrors: results.errors,
    success: results.errors.length === 0
  }
}];

// ─────────────────────────────────────────────────────────────
// ERROR HANDLER: Mark file as processed: error
// Updates the original brain dump file frontmatter to indicate
// processing failed, so it is not retried endlessly.
// ─────────────────────────────────────────────────────────────
const fs = require('fs');

const filePath = $input.item.json.filePath;
const fileName = $input.item.json.fileName;
const errorMessage = $input.item.json.errorMessage || 'Unknown error';

const now = new Date();
const timestamp = `${now.toISOString().slice(0, 10)}T${now.toISOString().slice(11, 19)}`;

try {
  let content = fs.readFileSync(filePath, 'utf8');
  content = content.replace(
    /processed:\s*false/,
    `processed: error\nprocessed_at: ${timestamp}\nerror_message: "${errorMessage.replace(/"/g, "'")}"`
  );
  fs.writeFileSync(filePath, content, 'utf8');
} catch (err) {
  // If we can't even write the error status, log it
  console.error(`Failed to mark ${fileName} as error: ${err.message}`);
}

return [{
  json: {
    filePath,
    fileName,
    errorMessage,
    markedAsError: true,
    timestamp
  }
}];

// ─────────────────────────────────────────────────────────────
// COMPLETION SUMMARY LOG
// Aggregates results from all processed files in this cycle.
// ─────────────────────────────────────────────────────────────
const items = $input.all();

let totalTasks = 0;
let totalNotes = 0;
let successCount = 0;
let errorCount = 0;
const details = [];

for (const item of items) {
  const d = item.json;
  if (d.success !== undefined) {
    // From Write Tasks & Notes node
    totalTasks += d.tasksWritten || 0;
    totalNotes += d.notesWritten || 0;
    if (d.success) successCount++;
    else errorCount++;
    details.push({
      file: d.fileName,
      tasks: d.tasksWritten,
      notes: d.notesWritten,
      status: d.success ? 'success' : 'partial'
    });
  } else if (d.markedAsError) {
    // From error handler
    errorCount++;
    details.push({
      file: d.fileName,
      status: 'error',
      error: d.errorMessage
    });
  }
}

const summary = {
  timestamp: new Date().toISOString(),
  filesProcessed: successCount + errorCount,
  successCount,
  errorCount,
  totalTasksCreated: totalTasks,
  totalNotesCreated: totalNotes,
  details
};

console.log(`Brain Dump Processor: ${summary.filesProcessed} files processed (${successCount} ok, ${errorCount} errors). ${totalTasks} tasks, ${totalNotes} notes created.`);

return [{ json: summary }];
